 1	import { type FC, useCallback } from 'react';
 2	import { PlanStatuses } from 'src/plans/details/components/PlanStatus/utils/types';
 3	import { getPlanStatus } from 'src/plans/details/components/PlanStatus/utils/utils';
 4	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
 5	
 6	import ModalForm from '@components/ModalForm/ModalForm';
 7	import { PlanModel, type V1beta1Plan } from '@kubev2v/types';
 8	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
 9	import { ButtonVariant, Stack, StackItem } from '@patternfly/react-core';
10	import { getName } from '@utils/crds/common/selectors';
11	import { getPlanArchived } from '@utils/crds/plans/selectors';
12	
13	type ArchiveModalProps = {
14	  plan: V1beta1Plan;
15	};
16	
17	const ArchiveModal: FC<ArchiveModalProps> = ({ plan }) => {
18	  const { t } = useForkliftTranslation();
19	
20	  const onArchive = useCallback(async () => {
21	    const op = getPlanArchived(plan) ? 'replace' : 'add';
22	
23	    return k8sPatch({
24	      data: [{ op, path: '/spec/archived', value: true }],
25	      model: PlanModel,
26	      resource: plan,
27	    });
28	  }, [plan]);
29	
30	  const status = getPlanStatus(plan);
31	  const isPlanRunning = status === PlanStatuses.Executing;
32	
33	  return (
34	    <ModalForm
35	      confirmLabel={t('Archive')}
36	      confirmVariant={isPlanRunning ? ButtonVariant.danger : ButtonVariant.primary}
37	      title={t('Archive migration plan')}
38	      onConfirm={onArchive}
39	    >
40	      <ForkliftTrans>
41	        <Stack hasGutter>
42	          <StackItem>
43	            Archive plan <strong className="co-break-word">{getName(plan)}</strong>?
44	          </StackItem>
45	          <StackItem>
46	            When a plan is archived, its history, metadata, and logs are deleted. The plan cannot be
47	            edited or restarted but it can be viewed.
48	          </StackItem>
49	        </Stack>
50	      </ForkliftTrans>
51	    </ModalForm>
52	  );
53	};
54	
55	export default ArchiveModal;

